class Solution:
    def canChange(self, start: str, target: str) -> bool:
        s = []
        t = []
        for c in start:
            if c != '_':
                s.append(c)
        for c in target:
            if c != '_':
                t.append(c)
        if s != t:
            return False
        si = 0
        ti = 0
        while si < len(start):
            if start[si] == target[si]:
                si += 1
                continue
            elif start[si] == 'L' and target[si] == '_':
                while si < len(start) and start[si] == '_':
                    si += 1
                if si == len(start):
                    return False
                if start[si] != 'L':
                    return False
            elif start[si] == 'R' and target[si] == '_':
                while si < len(start) and start[si] == '_':
                    si += 1
                if si == len(start):
                    return False
                if start[si] != 'R':
                    return False
            else:
                return False
        return True
